// Check WhatsApp Cloud API status
const https = require('https');

// WhatsApp Cloud API check (Meta's endpoint)
const options = {
  hostname: 'graph.facebook.com',
  port: 443,
  path: '/v18.0/me',
  method: 'GET',
  headers: {
    'Authorization': 'Bearer ' + $env.WHATSAPP_TOKEN
  },
  timeout: 5000
};

return new Promise((resolve) => {
  const req = https.request(options, (res) => {
    resolve({ status: res.statusCode, channel: 'whatsapp', available: res.statusCode === 200 });
  });
  req.on('error', () => resolve({ status: 0, channel: 'whatsapp', available: false }));
  req.on('timeout', () => { req.destroy(); resolve({ status: 0, channel: 'whatsapp', available: false }); });
  req.end();
});

// Check Telegram Bot API status
const https = require('https');

const options = {
  hostname: 'api.telegram.org',
  port: 443,
  path: '/bot' + $env.TELEGRAM_BOT_TOKEN + '/getMe',
  method: 'GET',
  timeout: 5000
};

return new Promise((resolve) => {
  const req = https.request(options, (res) => {
    let data = '';
    res.on('data', chunk => data += chunk);
    res.on('end', () => {
      try {
        const json = JSON.parse(data);
        resolve({ status: res.statusCode, channel: 'telegram', available: json.ok === true });
      } catch {
        resolve({ status: res.statusCode, channel: 'telegram', available: false });
      }
    });
  });
  req.on('error', () => resolve({ status: 0, channel: 'telegram', available: false }));
  req.on('timeout', () => { req.destroy(); resolve({ status: 0, channel: 'telegram', available: false }); });
  req.end();
});

// Merge status from both channels
const wa = $input.all()[0].json;
const tg = $input.all()[1].json;

const result = {
  timestamp: new Date().toISOString(),
  whatsapp: { available: wa.available, status: wa.status },
  telegram: { available: tg.available, status: tg.status },
  primary: wa.available ? 'whatsapp' : (tg.available ? 'telegram' : 'none'),
  failover_cta: wa.available ? 'https://t.me/buncheng' : 'https://wa.me/2347032981049'
};

return [{ json: result }];
